// Normaliza payload do Meta WhatsApp Cloud API
// Formato: entry[].changes[].value.messages[]
const body = $input.first().json.body;
const items = [];

if (!body || !body.entry) {
  return [{ json: { skip: true, reason: 'no_entry' } }];
}

for (const entry of body.entry) {
  for (const change of entry.changes || []) {
    const value = change.value || {};
    const phoneNumberId = value.metadata?.phone_number_id;
    const contacts = value.contacts || [];
    const messages = value.messages || [];
    const statuses = value.statuses || [];

    // Processa mensagens recebidas
    for (const msg of messages) {
      const contact = contacts.find(c => c.wa_id === msg.from) || {};

      // Extrai texto de diferentes tipos
      let text = '';
      switch (msg.type) {
        case 'text':
          text = msg.text?.body || '';
          break;
        case 'button':
          text = msg.button?.text || '';
          break;
        case 'interactive':
          if (msg.interactive?.type === 'button_reply') text = msg.interactive.button_reply.title;
          else if (msg.interactive?.type === 'list_reply') text = msg.interactive.list_reply.title;
          break;
        default:
          text = `[${msg.type}]`;
      }

      items.push({
        json: {
          source: 'meta',
          phoneNumberId,
          phone: msg.from,
          messageId: msg.id,
          timestamp: msg.timestamp,
          pushName: contact.profile?.name || '',
          messageType: msg.type,
          text,
          raw: msg
        }
      });
    }

    // Ignora status updates (delivered, read, etc)
    for (const status of statuses) {
      // Opcionalmente loga ou processa
      items.push({
        json: {
          source: 'meta',
          skip: true,
          phone: status.recipient_id,
          messageId: status.id,
          statusType: status.status,
          reason: 'status_update'
        }
      });
    }
  }
}

return items.length ? items : [{ json: { skip: true, reason: 'no_messages' } }];

const text = ($input.first().json.text || '').toLowerCase().trim();

let intent = 'DESCONHECIDA';
let confidence = 0.0;

const patterns = {
  SAUDACAO: [/^(oi|ol[aá]|bom dia|boa tarde|boa noite|hey|eae|salve)/i],
  AGENDAR: [/agendar|marcar|consulta|horário|agenda|quero.*consulta|preciso.*consulta/i],
  CANCELAR: [/cancelar|desmarcar|n[aã]o vou|n[aã]o posso|anular/i],
  REAGENDAR: [/remarcar|mudar|trocar|reagendar|outro dia|outro hor[aá]rio/i],
  CONSULTAR: [/minha consulta|próxima|quando é|quando vou|meus agendamentos/i],
  INFO: [/endere[çc]o|conv[eê]nio|pre[çc]o|valor|como funciona|funcionamento|hor[aá]rio de atendimento/i],
  HUMANO: [/atendente|humano|pessoa|algu[eé]m|recep[çc][aã]o|ligar/i]
};

for (const [key, regs] of Object.entries(patterns)) {
  for (const r of regs) {
    if (r.test(text)) { intent = key; confidence = 0.8; break; }
  }
  if (intent !== 'DESCONHECIDA') break;
}

if (/^[1-6]$/.test(text)) {
  intent = { '1': 'AGENDAR', '2': 'CONSULTAR', '3': 'CANCELAR', '4': 'REAGENDAR', '5': 'INFO', '6': 'HUMANO' }[text];
  confidence = 0.95;
}

return { json: { ...$input.first().json, intent, confidence, normalizedText: text } };

const data = $input.first().json;
const intent = data.intent;

let reply = '';

switch (intent) {
  case 'SAUDACAO':
  case 'DESCONHECIDA':
    reply = `Olá, ${data.pushName || 'tudo bem'}? 👋

Sou a assistente virtual da *Clínica Vida*. Como posso te ajudar hoje?

*1️⃣* Agendar consulta
*2️⃣* Ver meus agendamentos
*3️⃣* Cancelar consulta
*4️⃣* Remarcar consulta
*5️⃣* Informações (endereço, convênios)
*6️⃣* Falar com atendente

_Digite o número da opção_`;
    break;
  case 'INFO':
    reply = `📍 *Clínica Vida*

*Endereço:* Rua das Flores, 123 — Centro
*Horário:* Seg-Sex 7h-19h · Sáb 7h-12h
*Convênios:* Unimed, Amil, SulAmérica, Bradesco Saúde
*Particular:* a partir de R$ 250

Quer *agendar* agora? É só digitar *1*.`;
    break;
  case 'HUMANO':
    reply = `Vou te transferir para um atendente humano 👩‍💼

Por favor, descreva brevemente o assunto. Em horário comercial o retorno é em até *5 minutos*.`;
    break;
  case 'AGENDAR':
    reply = `Ótimo! Vamos agendar 😊

Qual especialidade você precisa?

*1️⃣* Clínico Geral
*2️⃣* Cardiologia
*3️⃣* Dermatologia
*4️⃣* Ginecologia
*5️⃣* Pediatria
*6️⃣* Ortopedia

Responde com o número da especialidade.`;
    break;
  default:
    reply = `Desculpa, não entendi 🤔

Digite *menu* para ver as opções ou escolha um número de 1 a 6.`;
}

return { json: { ...data, reply } };
